/**
 * DEMO & COMPONENTS PAGES
 */
test.describe('Demo & Components Pages', () => {
  const DEMO_PAGES = [
    { path: '/admin/components-demo.html', name: 'Components Demo', keywords: ['components', 'ui', 'demo'] },
    { path: '/admin/ui-components-demo.html', name: 'UI Components Demo', keywords: ['ui', 'components', 'material'] },
    { path: '/admin/ui-demo.html', name: 'UI Demo', keywords: ['ui', 'demo', 'interface'] },
    { path: '/admin/ux-components-demo.html', name: 'UX Components Demo', keywords: ['ux', 'components', 'experience'] },
    { path: '/admin/widgets-demo.html', name: 'Widgets Demo', keywords: ['widgets', 'demo', 'dashboard'] },
    { path: '/admin/features-demo.html', name: 'Features Demo', keywords: ['features', 'demo', 'showcase'] },
    { path: '/admin/features-demo-2027.html', name: 'Features Demo 2027', keywords: ['features', '2027', 'future'] },
  ];

  for (const page of DEMO_PAGES) {
    test.describe(`${page.name}`, () => {
      test('loads without critical errors', async ({ page: p }) => {
        const errors: string[] = [];

        p.on('pageerror', (error) => {
          if (error.message.includes('supabase') || error.message.includes('__ENV__')) return;
          if (error.message.includes('CustomElementRegistry')) return;
          if (error.message.includes('hover') || error.message.includes('touch')) return;
          errors.push(error.message);
        });

        const response = await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });
        expect(response?.status()).toBe(200);
        expect(errors.length).toBeLessThanOrEqual(5);
      });

      test('has valid title', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });
        const title = await p.title();
        expect(title.length).toBeGreaterThan(0);
        expect(title.toLowerCase()).toContain(page.keywords[0]);
      });
    });
  }
});

