/**
 * RESPONSIVE CHECK FOR ALL NEW PAGES
 */
test.describe('Responsive Check - New Pages', () => {
  const ALL_NEW_PAGES = [
    // Demo pages
    '/admin/components-demo.html',
    '/admin/ui-components-demo.html',
    '/admin/ui-demo.html',
    '/admin/ux-components-demo.html',
    '/admin/widgets-demo.html',
    '/admin/features-demo.html',
    '/admin/features-demo-2027.html',
    // F&B pages
    '/admin/menu.html',
    '/admin/pos.html',
    '/admin/inventory.html',
    '/admin/suppliers.html',
    '/admin/quality.html',
    // Business pages
    '/admin/hr-hiring.html',
    '/admin/lms.html',
    '/admin/loyalty.html',
    '/admin/pricing.html',
    '/admin/proposals.html',
    '/admin/raas-overview.html',
    '/admin/vc-readiness.html',
    '/admin/zalo.html',
    // Portal
    '/portal/assets.html',
    '/portal/notifications.html',
    // Affiliate
    '/affiliate/links.html',
    '/affiliate/settings.html',
  ];

  test('renders on mobile viewport (375px)', async ({ browser }) => {
    const context = await browser.newContext({
      viewport: { width: 375, height: 667 },
    });
    const page = await context.newPage();

    for (const path of ALL_NEW_PAGES) {
      await test.step(`Check ${path} on mobile`, async () => {
        const response = await page.goto(path, { waitUntil: 'commit', timeout: 30000 });
        expect(response?.status()).toBe(200);

        // Check viewport meta
        const viewport = await page.getAttribute('meta[name="viewport"]', 'content');
        expect(viewport).toBeTruthy();
      });
    }

    await context.close();
  });

  test('renders on tablet viewport (768px)', async ({ browser }) => {
    const context = await browser.newContext({
      viewport: { width: 768, height: 1024 },
    });
    const page = await context.newPage();

    for (const path of ALL_NEW_PAGES) {
      await test.step(`Check ${path} on tablet`, async () => {
        const response = await page.goto(path, { waitUntil: 'commit', timeout: 30000 });
        expect(response?.status()).toBe(200);
      });
    }

    await context.close();
  });

  test('renders on desktop viewport (1024px)', async ({ browser }) => {
    const context = await browser.newContext({
      viewport: { width: 1024, height: 768 },
    });
    const page = await context.newPage();

    for (const path of ALL_NEW_PAGES) {
      await test.step(`Check ${path} on desktop`, async () => {
        const response = await page.goto(path, { waitUntil: 'commit', timeout: 30000 });
        expect(response?.status()).toBe(200);
      });
    }

    await context.close();
  });
});

